    data: {
      labels: metrics.loadTime.map(d => new Date(d.timestamp).toLocaleTimeString()),
      datasets: [{
        label: '应用加载时间 (ms)',
        data: metrics.loadTime.map(d => d.duration),
        borderColor: '#4CAF50'
      }]
    }
  });
};
