constructor(apps, router) {
this.apps = apps;
this.router = router;
}

// 跳转到指定应用的指定路径
navigateTo(appName, path, query = {}) {
const app = this.apps.find(a => a.name === appName);
if (!app) {
console.error(`应用 ${appName} 不存在`);
return false;
}

// 构建完整路径
