class ResourcePreloader {
    constructor() {
        this.cache = new Map();
    }

    preload(url) {
        if (this.cache.has(url)) {
            return Promise.resolve(this.cache.get(url));
        }

        const promise = fetch(url)
            .then(response => response.json())
            .then(data => {
                this.cache.set(url, data);
                return data;
