Promise.all([promise1, promise2, promise3])
    .then(results => {
        // 如果任何一个 Promise 失败，这里都不会执行
    });

// ✅ 正确做法：为每个 Promise 添加错误处理
Promise.all([
    promise1.catch(err => ({ error: err })),
    promise2.catch(err => ({ error: err })),
    promise3.catch(err => ({ error: err }))
])
.then(results => {
