```javascript
// ❌ 潜在问题：事件监听器中的 Promise
class DataLoader {
    constructor() {
        this.listener = this.handleData.bind(this);
        eventEmitter.on('data', this.listener);
    }

    async handleData(data) {
        await this.processData(data);  // 如果组件被销毁，这个 Promise 可能永远挂着
    }
