## 12. 详细错误处理指南

### 12.1 错误类型分类
```javascript
class NetworkError extends Error {
    constructor(message) {
        super(message);
        this.name = 'NetworkError';
    }
}

class ValidationError extends Error {
    constructor(message) {
        super(message);
        this.name = 'ValidationError';
    }
}

class TimeoutError extends Error {
    constructor(message) {
        super(message);
        this.name = 'TimeoutError';
    }
}

// 使用示例
async function fetchWithErrorHandling(url) {
    try {
        const response = await fetch(url);

        if (!response.ok) {
            switch (response.status) {
                case 404:
                    throw new ValidationError('Resource not found');
                case 401:
                    throw new ValidationError('Unauthorized');
                case 503:
                    throw new NetworkError('Service unavailable');
                default:
                    throw new Error(`HTTP error! status: ${response.status}`);
            }
        }

        return await response.json();
    } catch (error) {
        if (error instanceof ValidationError) {
            // 处理验证错误
            console.error('Validation error:', error.message);
            return null;
        } else if (error instanceof NetworkError) {
            // 处理网络错误
            console.error('Network error:', error.message);
            throw error; // 重新抛出网络错误
        } else {
            // 处理其他错误
            console.error('Unexpected error:', error);
            throw error;
        }
    }
}
```

### 12.2 全局错误处理
```javascript
class ErrorHandler {
    static handle(error) {
        if (error instanceof ValidationError) {
            // 处理验证错误
            this.handleValidationError(error);
        } else if (error instanceof NetworkError) {
            // 处理网络错误
            this.handleNetworkError(error);
        } else if (error instanceof TimeoutError) {
            // 处理超时错误
            this.handleTimeoutError(error);
        } else {
            // 处理未知错误
            this.handleUnknownError(error);
        }
    }

    static handleValidationError(error) {
        console.error('Validation Error:', error.message);
        // 显示用户友好的错误消息
    }

    static handleNetworkError(error) {
        console.error('Network Error:', error.message);
        // 尝试重新连接
    }

    static handleTimeoutError(error) {
        console.error('Timeout Error:', error.message);
        // 提示用户重试
    }

    static handleUnknownError(error) {
        console.error('Unknown Error:', error);
        // 记录错误并通知开发团队
    }
}

// 使用示例
window.addEventListener('unhandledrejection', event => {
    ErrorHandler.handle(event.reason);
});
```

## 13. 性能优化最佳实践

### 13.1 Promise 批处理
```javascript
class PromiseBatcher {
    constructor(batchSize = 100, interval = 50) {
        this.batchSize = batchSize;
        this.interval = interval;
        this.queue = [];
        this.pending = false;
    }

    add(item) {
        return new Promise((resolve, reject) => {
            this.queue.push({ item, resolve, reject });
            this.process();
        });
    }

    async process() {
        if (this.pending || this.queue.length === 0) return;
        this.pending = true;

        await new Promise(resolve => setTimeout(resolve, this.interval));

        const batch = this.queue.splice(0, this.batchSize);
        const items = batch.map(({ item }) => item);

        try {
            const results = await this.processBatch(items);
            batch.forEach(({ resolve }, index) => resolve(results[index]));
        } catch (error) {
            batch.forEach(({ reject }) => reject(error));
        }

        this.pending = false;
        if (this.queue.length > 0) {
            this.process();
        }
    }

    async processBatch(items) {
        // 实现批处理逻辑
        return items.map(item => `Processed ${item}`);
    }
}

// 使用示例
const batcher = new PromiseBatcher();
for (let i = 0; i < 1000; i++) {
    batcher.add(i).then(result => console.log(result));
}
```

### 13.2 Promise 缓存优化
```javascript
class PromiseCache {
    constructor(ttl = 60000) { // 默认缓存时间 1 分钟
        this.cache = new Map();
        this.ttl = ttl;
    }

    async get(key, promiseFactory) {
        const cached = this.cache.get(key);
        if (cached && Date.now() - cached.timestamp < this.ttl) {
            return cached.data;
        }

        const data = await promiseFactory();
        this.cache.set(key, {
            data,
            timestamp: Date.now()
        });
        return data;
    }

    invalidate(key) {
        this.cache.delete(key);
    }

    clear() {
        this.cache.clear();
    }
}

// 使用示例
const cache = new PromiseCache();
async function fetchUserWithCache(userId) {
    return cache.get(
        `user_${userId}`,
        () => fetch(`/api/users/${userId}`).then(r => r.json())
    );
}
```

### 13.3 内存优化
```javascript
class MemoryEfficientPromise {
    static async batch(items, processor, batchSize = 100) {
        const results = [];
        for (let i = 0; i < items.length; i += batchSize) {
            const batch = items.slice(i, i + batchSize);
            const batchResults = await Promise.all(
                batch.map(processor)
            );
            results.push(...batchResults);

            // 允许垃圾回收
            await new Promise(resolve => setTimeout(resolve, 0));
        }
        return results;
    }

    static async stream(asyncIterable, processor) {
        const results = [];
        for await (const item of asyncIterable) {
            results.push(await processor(item));

            // 定期清理
            if (results.length % 1000 === 0) {
                await new Promise(resolve => setTimeout(resolve, 0));
            }
        }
        return results;
    }
}

// 使用示例
const items = Array.from({ length: 10000 }, (_, i) => i);
MemoryEfficientPromise.batch(items, async (item) => {
    // 处理每个项目
    return item * 2;
}).then(results => console.log('Processed items:', results.length));
