## 3. 构建基础

### 3.1 开发服务器
```javascript
// vite.config.js
export default defineConfig({
  server: {
    port: 3000,
    open: true,
    proxy: {
      '/api': {
        target: 'http://localhost:8080',
        changeOrigin: true,
        rewrite: (path) => path.replace(/^\/api/, '')
      }
    }
  }
})
```

### 3.2 构建配置
```javascript
export default defineConfig({
  build: {
    target: 'modules',
    outDir: 'dist',
    assetsDir: 'assets',
    minify: 'terser',
    rollupOptions: {
      output: {
        manualChunks: {
          'vendor': ['vue', 'vue-router']
        }
      }
    }
  }
})
```

## 4. 资源处理

### 4.1 静态资源
```javascript
// 图片资源
import imgUrl from './img.png'
document.getElementById('hero').src = imgUrl

// CSS 模块
import styles from './style.module.css'
element.className = styles.heading

// JSON
import data from './data.json'
console.log(data)
```

### 4.2 样式处理
```javascript
// CSS 预处理器
