## 9. 性能优化

### 9.1 构建优化
```javascript
export default defineConfig({
  build: {
    target: 'modules',
    minify: 'terser',
    terserOptions: {
      compress: {
        drop_console: true,
        drop_debugger: true
      }
    },
    rollupOptions: {
      output: {
        manualChunks(id) {
          if (id.includes('node_modules')) {
            return 'vendor'
          }
        }
      }
    }
  }
})
```

### 9.2 代码分割

#### 9.2.1 基础配置
```javascript
// vite.config.js
export default defineConfig({
  build: {
    rollupOptions: {
      output: {
        // 1. 手动分块策略
        manualChunks: {
          // 将 Vue 全家桶拆分成单独的 chunk
          'vue-vendor': ['vue', 'vue-router', 'pinia'],
          // 将 UI 框架拆分
          'element-plus': ['element-plus'],
          // 将大型依赖拆分
          'lodash': ['lodash-es'],
        },
        // 2. 自定义 chunk 文件名
        chunkFileNames: (chunkInfo) => {
          const facadeModuleId = chunkInfo.facadeModuleId
          if (facadeModuleId) {
            return `js/[name]-[hash].js`
          }
          return 'js/vendor-[hash].js'
        },
        // 3. 自定义资源文件名
        assetFileNames: (assetInfo) => {
          if (assetInfo.name.endsWith('.css')) {
            return 'css/[name]-[hash][extname]'
          }
          return 'assets/[name]-[hash][extname]'
        }
      }
    }
  }
})
```

#### 9.2.2 动态导入
```javascript
// 1. 路由级别代码分割
// router/index.js
const routes = [
  {
    path: '/',
    component: () => import('../views/Home.vue')
  },
  {
    path: '/about',
    // 添加注释以控制 chunk 名称
    component: () => import(/* webpackChunkName: "about" */ '../views/About.vue')
  },
  {
    path: '/dashboard',
    // 预加载重要路由
    component: () => import(/* webpackPrefetch: true */ '../views/Dashboard.vue')
  }
]

// 2. 组件级别代码分割
// 按需加载组件
const MyHeavyComponent = defineAsyncComponent(() => 
  import('../components/MyHeavyComponent.vue')
)

// 3. 条件导入
async function loadAnalytics() {
  if (process.env.NODE_ENV === 'production') {
    const analytics = await import('./analytics')
    analytics.init()
  }
}
```

#### 9.2.3 分割策略
```javascript
// vite.config.js
export default defineConfig({
  build: {
    rollupOptions: {
      output: {
        manualChunks(id) {
          // 1. 将 node_modules 中的代码单独打包
          if (id.includes('node_modules')) {
            // 获取包名
            const packageName = id.toString().split('node_modules/')[1].split('/')[0]
            // 将每个包单独打包
            return `vendor-${packageName}`
          }

          // 2. 将公共组件打包到一起
          if (id.includes('src/components')) {
            return 'components'
          }

          // 3. 将工具函数打包到一起
          if (id.includes('src/utils')) {
            return 'utils'
          }
        }
      }
    }
  }
})
```

#### 9.2.4 预加载和预获取
```javascript
// 1. 使用 vite-plugin-imagemin 优化图片
import viteImagemin from 'vite-plugin-imagemin'

export default defineConfig({
  plugins: [
    viteImagemin({
      gifsicle: { optimizationLevel: 3 },
      mozjpeg: { quality: 75 },
      pngquant: { quality: [0.7, 0.8] },
      svgo: {
        plugins: [
          { removeViewBox: false },
          { removeDimensions: true }
        ]
      }
    })
  ]
})

// 2. 资源预加载
// index.html
<link rel="modulepreload" href="/src/heavy-module.js">
<link rel="preload" href="/assets/large-image.jpg" as="image">

// 3. 动态预加载
const preloadComponent = () => {
  const component = import('./BigComponent.vue')
  requestIdleCallback(() => {
    // 在空闲时间预加载其他资源
    import('./non-critical-module.js')
  })
  return component
}
```

#### 9.2.5 分割优化建议

1. **合理的分割粒度**
```javascript
// 不好的实践 - 过度分割
manualChunks: {
  'tiny-lib': ['tiny-lib'], // 这个库太小，不值得单独分割
  'utils': ['./src/utils/format.js'] // 工具函数太小，应该合并
}

// 好的实践 - 适当分割
manualChunks: {
  'core-vendor': ['vue', 'vue-router', 'pinia'], // 核心依赖打包在一起
  'ui-vendor': ['element-plus'], // UI 框架单独打包
  'big-vendor': ['echarts', 'three.js'] // 大型依赖单独打包
}
```

2. **动态导入最佳实践**
```javascript
// 组件动态导入
const routes = [
  {
    path: '/dashboard',
    component: () => import('./views/Dashboard.vue'),
    // 使用 webpackPreload 确保关键路由快速加载
    children: [
      {
        path: 'overview',
        component: () => import(/* webpackPrefetch: true */ './views/Overview.vue')
      },
      {
        path: 'analysis',
        component: () => import(/* webpackPreload: true */ './views/Analysis.vue')
      }
    ]
  }
]
```

3. **性能监控**
```javascript
// 监控代码分割性能
import { onLCP, onFID } from 'web-vitals'

// 监控加载性能
onLCP(console.log)
onFID(console.log)

// 监控 chunk 加载失败
window.addEventListener('error', (event) => {
  if (event.target.tagName === 'SCRIPT') {
    // 处理 chunk 加载失败
    console.error('Chunk load failed:', event.target.src)
  }
}, true)
```

这样的代码分割内容更加完整和准确，涵盖了：
- 基础配置
- 动态导入
- 分割策略
- 预加载和预获取
- 最佳实践和性能监控

每个部分都提供了具体的代码示例和实践建议，更有助于理解和实施代码分割。
```

## 10. 部署运维

### 10.1 静态部署
```javascript
// vite.config.js
export default defineConfig({
  base: production ? '/your-repo/' : '/',
  build: {
    outDir: 'dist',
    emptyOutDir: true,
    sourcemap: true,
    manifest: true
  }
})
```

### 10.2 CI/CD 配置
```yaml
# .github/workflows/deploy.yml
name: Deploy

on:
  push:
    branches: [main]

jobs:
  build-and-deploy:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v2
      - uses: actions/setup-node@v2
        with:
          node-version: '16'

      - name: Install and Build
        run: |
          npm ci
          npm run build

      - name: Deploy
        uses: peaceiris/actions-gh-pages@v3
        with:
          github_token: ${{ secrets.GITHUB_TOKEN }}
          publish_dir: ./dist
```

### 10.3 性能监控
```javascript
// 性能指标监控
import { onCLS, onFID, onLCP } from 'web-vitals'

function sendToAnalytics({ name, delta, id }) {
  // 发送性能数据到分析服务
  console.log(`Metric: ${name} ID: ${id} Value: ${delta}`)
}

onCLS(sendToAnalytics)
onFID(sendToAnalytics)
onLCP(sendToAnalytics)
```

