  const version = Taro.getSystemInfoSync().SDKVersion

  // 比较版本号
  if (Taro.compareVersion(version, '2.21.0') < 0) {
    Taro.showModal({
      title: '提示',
      content: '当前微信版本过低，请更新至最新版本',
      showCancel: false
    })
  }
}
```

### 🎨 WeUI 组件使用

```typescript
// app.config.ts
export default {
  // ...
  useExtendedLib: {
    weui: true
  }
}
```

使用示例：
```vue
<template>
  <weui-form>
    <weui-cells title="表单">
      <weui-cell>
        <weui-input placeholder="请输入" />
      </weui-cell>
    </weui-cells>
    <weui-button type="primary">提交</weui-button>
  </weui-form>
</template>
```

