### 🔑 小程序登录流程优化

#### 完整登录流程图

<img src="/img/taroLogin.png" 
     srcset="/img/taroLogin.png 480w, /img/taroLogin.png 1200w" 
     sizes="(max-width:600px) 100vw, 50vw">

#### 登录流程说明

1. **本地验证阶段**：
   - 检查本地是否有登录凭证(token)
   - 若有token，验证其有效性
   - 若无token或token无效，进入微信登录流程

2. **获取凭证阶段**：
   - 调用`Taro.login()`获取临时登录凭证code
   - 将code发送至应用服务器

3. **服务端身份验证**：
   - 应用服务器携带code、appid和secret请求微信服务器
   - 微信服务器返回openid和session_key
   - 应用服务器根据openid查询用户是否存在

4. **用户处理阶段**：
   - 若用户已存在：更新用户登录时间，生成新token
   - 若用户不存在：创建新用户记录，生成token
   - 将token和用户基本信息返回小程序前端

5. **登录完成阶段**：
   - 小程序保存token到本地存储
   - 保存必要的用户信息
   - 更新应用的登录状态
   - 进入小程序主界面

#### 代码实现

##### 前端实现（Taro）

```typescript
// login.ts
import Taro from '@tarojs/taro'
import { login as apiLogin } from '../services/auth'

// 登录状态检查与登录流程
export async function ensureLogin() {
  // 1. 检查本地是否有有效的 token
  const token = Taro.getStorageSync('token')

  if (token) {
    try {
      // 2. 验证 token 是否有效
      const checkResult = await checkTokenValidity(token)
      if (checkResult.valid) {
        console.log('token 有效，已登录')
        return true
      }
    } catch (err) {
      console.log('token 校验失败，需要重新登录')
    }
  }

  // 3. token 无效或不存在，进行登录流程
  return await wxLogin()
}

// 微信登录流程
async function wxLogin() {
  try {
    // 显示加载提示
    Taro.showLoading({ title: '登录中...' })

    // 4. 调用微信登录，获取 code
    const { code } = await Taro.login()
    if (!code) {
      throw new Error('微信登录失败，获取 code 失败')
    }

    // 5. 将 code 发送给后端
    const loginResult = await apiLogin({ code })

    // 6. 存储登录状态和用户信息
    Taro.setStorageSync('token', loginResult.token)
    Taro.setStorageSync('userInfo', loginResult.userInfo)

    // 判断是否是新用户，如果是新用户可以引导完善资料
    if (loginResult.isNewUser) {
      Taro.navigateTo({ url: '/pages/user-profile/index' })
    }

    Taro.hideLoading()
    return true
  } catch (error) {
    console.error('登录失败', error)
    Taro.hideLoading()

    Taro.showToast({
      title: '登录失败，请重试',
      icon: 'none'
    })

    return false
  }
}

// 校验 token 有效性
async function checkTokenValidity(token) {
  try {
    const res = await Taro.request({
      url: '/api/auth/check-token',
      header: {
        'Authorization': `Bearer ${token}`
      }
    })
    return { valid: res.data.valid }
  } catch (error) {
    return { valid: false }
  }
}
```

##### 服务端实现（Node.js）

```typescript
// auth.controller.ts
import { Request, Response } from 'express'
import axios from 'axios'
import jwt from 'jsonwebtoken'
import { User } from '../models/user.model'

// 微信登录配置
const WX_CONFIG = {
  appId: process.env.WX_APP_ID,
  appSecret: process.env.WX_APP_SECRET,
  loginUrl: 'https://api.weixin.qq.com/sns/jscode2session'
}

// 登录接口
export async function login(req: Request, res: Response) {
  try {
    const { code } = req.body

    if (!code) {
      return res.status(400).json({ 
        success: false, 
        message: '缺少登录code' 
      })
    }

    // 1. 请求微信API获取openid和session_key
    const wxResponse = await axios.get(WX_CONFIG.loginUrl, {
      params: {
        appid: WX_CONFIG.appId,
        secret: WX_CONFIG.appSecret,
        js_code: code,
        grant_type: 'authorization_code'
      }
    })

    const { openid, session_key } = wxResponse.data

    if (!openid) {
      return res.status(401).json({ 
        success: false, 
        message: '获取openid失败' 
      })
    }

    // 2. 根据openid查询数据库，判断用户是否存在
    let user = await User.findOne({ openid })
    let isNewUser = false

    // 3. 如果用户不存在，则创建新用户
    if (!user) {
      isNewUser = true
      user = await User.create({
        openid,
        createdAt: new Date(),
        // 其他默认数据
        nickname: `用户${Math.floor(Math.random() * 10000)}`,
        avatarUrl: '', // 默认头像
      })
    }

    // 4. 生成token
    const token = jwt.sign(
      { userId: user._id, openid },
      process.env.JWT_SECRET,
      { expiresIn: '7d' }
    )

    // 5. 更新用户的最后登录时间
    await User.updateOne(
      { _id: user._id },
      { $set: { lastLoginAt: new Date() } }
    )

    // 6. 返回登录结果
    return res.status(200).json({
      success: true,
      token,
      userInfo: {
        _id: user._id,
        nickname: user.nickname,
        avatarUrl: user.avatarUrl,
        // 其他需要的用户信息
      },
      isNewUser
    })

  } catch (error) {
    console.error('登录异常:', error)
    return res.status(500).json({
      success: false,
      message: '服务器错误'
    })
  }
}

// 验证token接口
export async function checkToken(req: Request, res: Response) {
  try {
    // token已经在中间件中验证过，能到这里说明token有效
    return res.status(200).json({
      valid: true
    })
  } catch (error) {
    return res.status(401).json({
      valid: false
    })
  }
}
```

#### 请求封装

```typescript
// request.ts
import Taro from '@tarojs/taro'
import { ensureLogin } from './login'

// 封装请求方法，自动携带token和处理登录态
export async function request(options) {
  // 获取存储的token
  const token = Taro.getStorageSync('token')

  // 合并请求头
  const header = {
    'Content-Type': 'application/json',
    ...options.header
  }

  // 如果有token，则添加到请求头
  if (token) {
    header['Authorization'] = `Bearer ${token}`
  }

  try {
    const response = await Taro.request({
      ...options,
      header
    })

    // 请求成功
    if (response.statusCode >= 200 && response.statusCode < 300) {
      return response.data
    }

    // token 失效（401）
    if (response.statusCode === 401) {
      // 清除已失效的token
      Taro.removeStorageSync('token')

      // 重新登录
      const loginSuccess = await ensureLogin()

      if (loginSuccess) {
        // 登录成功，重试原请求
        return request(options)
      } else {
        throw new Error('登录失败，无法完成请求')
      }
    }

    // 其他错误
    throw new Error(response.data.message || '请求失败')

  } catch (error) {
    console.error('请求异常:', error)
    throw error
  }
}
```

#### 登录状态管理（使用Pinia）

```typescript
// stores/user.ts
import { defineStore } from 'pinia'
import Taro from '@tarojs/taro'
import { ensureLogin } from '../utils/login'
import { getUserInfo } from '../services/user'

export const useUserStore = defineStore('user', {
  state: () => ({
    token: Taro.getStorageSync('token') || '',
    userInfo: Taro.getStorageSync('userInfo') || null,
    isLoggedIn: !!Taro.getStorageSync('token'),
    isLoading: false
  }),

  actions: {
    // 初始化检查登录状态
    async checkLoginStatus() {
      this.isLoading = true
      try {
        if (this.isLoggedIn) {
          // 刷新用户信息
          await this.fetchUserInfo()
        }
      } catch (error) {
        // 出错则置为未登录状态
        this.isLoggedIn = false
        this.token = ''
        this.userInfo = null
        Taro.removeStorageSync('token')
        Taro.removeStorageSync('userInfo')
      } finally {
        this.isLoading = false
      }
    },

    // 登录
    async login() {
      this.isLoading = true
      try {
        const success = await ensureLogin()
        if (success) {
          this.token = Taro.getStorageSync('token')
          this.userInfo = Taro.getStorageSync('userInfo')
          this.isLoggedIn = true
          return true
        }
        return false
      } catch (error) {
        console.error('登录失败', error)
        return false
      } finally {
        this.isLoading = false
      }
    },

    // 获取用户信息
    async fetchUserInfo() {
      if (!this.token) return

      try {
        const userInfo = await getUserInfo()
        this.userInfo = userInfo
        Taro.setStorageSync('userInfo', userInfo)
      } catch (error) {
        console.error('获取用户信息失败', error)
      }
    },

    // 退出登录
    logout() {
      this.token = ''
      this.userInfo = null
      this.isLoggedIn = false
      Taro.removeStorageSync('token')
      Taro.removeStorageSync('userInfo')
      Taro.showToast({ title: '已退出登录', icon: 'success' })
    }
  }
})
```

